111	  const handleSubmit = useCallback(() => {
112	    if (submitted) return;
113	    accrueCurrentQuestion();
114	    // Compute score
115	    let score = 0;
116	    const partialCredits: Record<string, number> = {};
117	    for (const question of quiz.questions) {
118	      const answer = (answers[question.id] ?? "").trim();
119	      if (question.type === "multi_select" && question.correctAnswers) {
120	        const selected = new Set(answer.split(",").map((s) => s.trim()).filter(Boolean));
121	        const correct = question.correctAnswers;
122	        const selectedCorrect = correct.filter((c) => selected.has(c)).length;
123	        const selectedWrong = Array.from(selected).filter((s) => !correct.includes(s)).length;
124	        const credit = selectedCorrect / correct.length - selectedWrong / (question.options?.length || 1);
125	        partialCredits[question.id] = Math.max(0, credit);
126	        if (credit >= 0.99) score++;
127	      } else if (question.type === "fill_in" && question.blanks && question.blanks.length > 0) {
128	        const userAnswers = answer.split("|").map((s) => s.trim());
129	        const correctAnswers = question.correctAnswers ?? [question.correctAnswer];
130	        let correct = 0;
131	        for (let i = 0; i < Math.min(userAnswers.length, correctAnswers.length); i++) {
132	          if (userAnswers[i].toLowerCase() === correctAnswers[i].trim().toLowerCase()) correct++;
133	        }
134	        partialCredits[question.id] = correct / correctAnswers.length;
135	        if (correct === correctAnswers.length) score++;
136	      } else {
137	        const correct = answer.toLowerCase() === question.correctAnswer.toLowerCase();
138	        if (correct) score++;
139	        partialCredits[question.id] = correct ? 1 : 0;
140	      }
141	    }
142	    const timing = {
143	      totalMs: Date.now() - startRef.current,
144	      perQuestionMs: { ...perQuestionRef.current },
145	    };
146	    const result: QuizResult = {
147	      answers,
148	      score,
149	      weightedScore: score,
150	      timing,
151	      confidence: {},
152	      partialCredits,
153	      flagged: Array.from(flagged),
154	    };
155	    setElapsedMs(timing.totalMs);
156	    setFinalTiming(timing);
157	    setSubmitted(true);
158	    onSubmit(result);
159	  }, [accrueCurrentQuestion, answers, flagged, onSubmit, quiz.questions, submitted]);
