// Ensure a main branch exists
// ---------------------------------------------------------------------------
async function ensureMainBranch() {
    const existing = await getByKey("branches", "main");
    if (existing)
        return existing;
    const main = {
        id: "main",
        name: "main",
        commitId: null,
        hidden: false,
        createdAt: new Date().toISOString(),
    };
    await put("branches", main);
