    main.commitId = commitId;
    await put("branches", main);
    return commitId;
}
async function lixListBranches() {
    await ensureInit();
    const rows = await getAll("branches");
    return rows
        .filter((b) => !b.hidden)
        .map((b) => ({
        id: b.id,
        name: b.name,
        commitId: b.commitId,
        hidden: b.hidden,
    }));
}
async function lixListCommits(branchId) {
    await ensureInit();
    const target = branchId ?? "main";
    const rows = await getByIndex("commits", "branchId", target);
    // newest first
    rows.sort((a, b) => b.createdAt.localeCompare(a.createdAt));
    return Promise.all(rows.map(async (c) => {
        const files = await getByIndex("commitFiles", "commitId", c.id);
        return {
            id: c.id,
            branchId: c.branchId,
            message: c.message,
            createdAt: c.createdAt,
            fileCount: files.length,
            files: files.map((f) => ({ path: f.path, hash: f.contentHash })),
        };
    }));
}
async function lixCreateBranch(name) {
    await ensureInit();
    const id = `branch-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;
    const main = await ensureMainBranch();
    const branch = {
        id,
        name,
        commitId: main.commitId,
        hidden: false,
        createdAt: new Date().toISOString(),
    };
    await put("branches", branch);
    return { id: branch.id, name: branch.name, commitId: branch.commitId, hidden: branch.hidden };
}
async function lixSwitchBranch(branchId) {
    await ensureInit();
    // lightweight impl: just update the "active" branch ref in a simple meta store
    await put("branches", { ...(await getByKey("branches", branchId) ?? await ensureMainBranch()), name: (await getByKey("branches", branchId))?.name ?? "main" });
    // Store active branch in localStorage for persistence
    localStorage.setItem("keating-vc-active-branch", branchId);
}
async function lixDiffCommits(fromCommitId, toCommitId) {
    const [fromFiles, toFiles] = await Promise.all([
        getByIndex("commitFiles", "commitId", fromCommitId),
        getByIndex("commitFiles", "commitId", toCommitId),
    ]);
    const fromMap = new Map(fromFiles.map((f) => [f.path, f.contentHash]));
    const toMap = new Map(toFiles.map((f) => [f.path, f.contentHash]));
    const allPaths = new Set([...fromMap.keys(), ...toMap.keys()]);
    const changes = [];
    for (const path of allPaths) {
        const fh = fromMap.get(path);
        const th = toMap.get(path);
        if (!fh)
            changes.push({ path, toHash: th, status: "added" });
        else if (!th)
            changes.push({ path, fromHash: fh, status: "removed" });
        else if (fh !== th)
            changes.push({ path, fromHash: fh, toHash: th, status: "modified" });
        else
            changes.push({ path, fromHash: fh, toHash: th, status: "unchanged" });
    }
    return changes;
}
async function exportSandboxVc() {
    await ensureInit();
    const [branches, commits, commitFiles] = await Promise.all([
        getAll("branches"),
        getAll("commits"),
        getAll("commitFiles"),
    ]);
    return {
        schemaVersion: 1,
        generatedAt: new Date().toISOString(),
        activeBranchId: localStorage.getItem("keating-vc-active-branch") ?? "main",
        branches,
        commits,
        commitFiles,
    };
}
