1047	const interactiveTagPattern = /<keating-(quiz|scene|question|goal|image|quiz-result|animation|deck)\s+(json|markdown)=([^>]+)\s*\/>/g;
1048	const URL_IN_TEXT_PATTERN = /\bhttps?:\/\/[^\s<>"')\]]+/i;
