1050	function parseInteractiveSegments(
1051	  text: string,
1052	): Array<
1053	  | { type: "text"; content: string }
1054	  | { type: "quiz"; json: string }
1055	  | { type: "scene"; markdown: string }
1056	  | { type: "question"; json: string }
1057	  | { type: "goal"; json: string }
1058	  | { type: "image"; json: string }
1059	  | { type: "quiz-result"; json: string }
1060	  | { type: "animation"; json: string }
1061	  | { type: "deck"; json: string }
1062	> {
1063	  const segments: ReturnType<typeof parseInteractiveSegments> = [];
1064	  let lastIndex = 0;
1065	
1066	  for (const match of text.matchAll(interactiveTagPattern)) {
1067	    const index = match.index ?? 0;
1068	    if (index > lastIndex) {
1069	      segments.push({ type: "text", content: text.slice(lastIndex, index) });
1070	    }
1071	
1072	    const tag = match[1];
1073	    const payload = match[3];
1074	    if (tag === "quiz") segments.push({ type: "quiz", json: payload });
1075	    if (tag === "quiz-result") segments.push({ type: "quiz-result", json: payload });
1076	    if (tag === "scene") {
1077	      let markdown = payload;
1078	      try {
1079	        markdown = JSON.parse(payload);
1080	      } catch {
1081	        // Older tags may already carry raw markdown.
1082	      }
1083	      segments.push({ type: "scene", markdown });
1084	    }
1085	    if (tag === "question") segments.push({ type: "question", json: payload });
1086	    if (tag === "goal") segments.push({ type: "goal", json: payload });
1087	    if (tag === "image") segments.push({ type: "image", json: payload });
1088	    if (tag === "animation") segments.push({ type: "animation", json: payload });
1089	    if (tag === "deck") segments.push({ type: "deck", json: payload });
1090	    lastIndex = index + match[0].length;
1091	  }
1092	
1093	  if (lastIndex < text.length) {
1094	    segments.push({ type: "text", content: text.slice(lastIndex) });
1095	  }
1096	  if (segments.length === 0) segments.push({ type: "text", content: text });
1097	  return segments;
1098	}
