1100	function stripQuestionTags(text: string): string {
1101	  return text.replace(questionTagPattern, "").trim();
1102	}
1103	
1104	function stripQuizTags(text: string): string {
1105	  let result = text;
1106	  for (const _match of text.matchAll(quizTagPattern)) {
1107	    result = result.replace(_match[0], "");
1108	  }
1109	  return result.trim();
1110	}
1111	
1112	function stripGoalTags(text: string): string {
1113	  return text.replace(goalTagPattern, "").trim();
1114	}
1115	
1116	function stripGeneratedImageTags(text: string): string {
1117	  return text.replace(generatedImageTagPattern, "").trim();
1118	}
1119	
1120	function extractLatestTagPayload(text: string, pattern: RegExp, captureIndex = 1): string | null {
1121	  pattern.lastIndex = 0;
1122	  let latest: string | null = null;
1123	  let match: RegExpExecArray | null;
1124	  while ((match = pattern.exec(text)) !== null) {
1125	    const capture = match[captureIndex];
1126	    if (typeof capture === "string") latest = capture;
1127	    if (match[0] === "") pattern.lastIndex += 1;
1128	  }
1129	  pattern.lastIndex = 0;
1130	  return latest;
1131	}

