// Holds the teacher's (model's) open-ended grades, keyed by quiz-result id, so a
// <keating-quiz-grade> tag emitted after the quiz can update the earlier result
// card. The card reads grades[data.id]; QuizGradeApplier writes them on mount.
interface QuizGradesContextValue {
  grades: Record<string, QuizQuestionGrade[]>;
  applyGrades: (resultId: string, grades: QuizQuestionGrade[]) => void;
}
const QuizGradesContext = createContext<QuizGradesContextValue>({
  grades: {},
  applyGrades: () => {},
});

/**
 * Renders nothing visible beyond a small confirmation; its job is to push the
 * model's grade payload into QuizGradesContext when the grade tag mounts.
 */
function QuizGradeApplier({ payload }: { payload: QuizGradePayload }) {
  const { applyGrades } = useContext(QuizGradesContext);
  useEffect(() => {
    if (payload.resultId && payload.grades.length > 0) {
      applyGrades(payload.resultId, payload.grades);
    }
  }, [payload, applyGrades]);
  return (
    <p className="my-1 text-xs text-muted-foreground italic">
      Reviewed your open-ended answers above.
    </p>
  );
}

